(function() {
  var PRICING = { 'deepseek-v4-flash': { hit: 0.02, miss: 1, output: 2 }, 'deepseek-v4-pro': { hit: 0.025, miss: 3, output: 6 } };
  var state = { currentSave: null, saves: {}, lastUsage: null, panelOpen: false, apiKey: '', balance: null, customBalance: null, settings: { autoBalance: false, balanceInterval: 10, debug: false, debugHit: 10000, debugMiss: 5000, debugOutput: 2000, debugModel: 'deepseek-v4-flash' }, messageCount: 0 };
  var isInitDone = false;
  var initTimestamp = 0;
  var PANEL_HTML = "<style>@media(max-width:480px){.ds-grid-3{grid-template-columns:repeat(2,1fr) !important}}</style><div style=\"margin-bottom:16px\"><div style=\"display:flex;gap:6px;margin-bottom:8px\"><select id=\"ds-save-select\" style=\"flex:1;min-width:0;padding:10px 12px;border:1px solid #374151;border-radius:8px;font-size:14px;background:#0e1520;color:#e5e7eb;outline:none;font-weight:500;font-family:system-ui,-apple-system,sans-serif;overflow:hidden;text-overflow:ellipsis\"><option value=\"\">加载中...</option></select><button id=\"ds-btn-new-save\" style=\"padding:10px 12px;border:1px solid #065f46;border-radius:8px;background:#065f46;color:#6ee7b7;font-size:12px;font-weight:600;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">+ 新建</button></div><div style=\"display:flex;gap:6px\"><button id=\"ds-btn-delete-save\" style=\"flex:1;padding:6px 10px;border:1px solid #7f1d1d;border-radius:6px;background:#7f1d1d;color:#fca5a5;font-size:11px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">删除当前存档</button><button id=\"ds-btn-delete-all\" style=\"flex:1;padding:6px 10px;border:1px solid #7f1d1d;border-radius:6px;background:#991b1b;color:#fecaca;font-size:11px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">清空全部存档</button></div></div><div id=\"ds-balance-box\" style=\"padding:14px;background:#0c1a2e;border:1px solid #2563eb;border-radius:10px;margin-bottom:4px\"><div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:8px\"><div style=\"font-size:12px;color:#93c5fd;font-weight:500\">账户余额</div><div style=\"display:flex;gap:6px\"><button id=\"ds-btn-query-balance\" style=\"padding:4px 10px;border:1px solid #3b82f6;border-radius:6px;background:#2563eb;color:white;font-size:11px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">查询</button></div></div><div id=\"ds-balance\" style=\"font-size:26px;font-weight:700;color:#60a5fa;font-family:system-ui,-apple-system,sans-serif\">¥0.00 CNY</div><div id=\"ds-balance-remaining\" style=\"font-size:14px;color:#34d399;margin-top:4px;font-weight:500;font-family:system-ui,-apple-system,sans-serif\"></div><div id=\"ds-balance-status\" style=\"font-size:11px;color:#93c5fd;margin-top:4px;font-weight:500\"></div></div><div id=\"ds-settings-toggle\" style=\"display:flex;align-items:center;justify-content:center;padding:6px 0;margin-bottom:12px;cursor:pointer;border:1px solid #374151;border-radius:0 0 8px 8px;background:#0a1018;border-top:none\"><span style=\"font-size:11px;color:#6b7280;font-weight:500;margin-right:6px\">展开设置</span><span id=\"ds-settings-arrow\" style=\"font-size:10px;color:#6b7280;transition:transform 0.2s\">▼</span></div><div id=\"ds-settings-panel\" style=\"display:none;margin-bottom:12px;padding:12px;background:#0e1520;border:1px solid #374151;border-radius:8px;max-height:60vh;overflow-y:auto;-webkit-overflow-scrolling:touch\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:8px;text-transform:uppercase;letter-spacing:0.5px\">设置</div><div style=\"display:flex;flex-direction:column;gap:10px\"><div style=\"margin-bottom:2px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px\">API密钥</div><div style=\"display:flex;gap:6px\"><input id=\"ds-api-key\" type=\"password\" placeholder=\"输入DeepSeek API密钥\" style=\"flex:1;padding:8px 10px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:13px;font-family:system-ui,-apple-system,sans-serif;outline:none\"><button id=\"ds-btn-save-key\" style=\"padding:8px 12px;border:1px solid #374151;border-radius:6px;background:#374151;color:#e5e7eb;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">保存</button></div></div><div style=\"border-top:1px solid #374151;padding-top:10px\"><div style=\"display:flex;align-items:center;justify-content:space-between\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">自动校准余额</span><label style=\"position:relative;display:inline-block;width:44px;height:24px;cursor:pointer\"><input type=\"checkbox\" id=\"ds-auto-balance\" style=\"opacity:0;width:0;height:0\"><span style=\"position:absolute;top:0;left:0;right:0;bottom:0;background:#374151;border-radius:12px;transition:0.3s;cursor:pointer\"><span id=\"ds-auto-balance-slider\" style=\"position:absolute;height:18px;width:18px;left:3px;bottom:3px;background:white;border-radius:50%;transition:0.3s\"></span></span></label></div><div id=\"ds-auto-balance-interval\" style=\"display:none;margin-top:8px\"><div style=\"display:flex;align-items:center;justify-content:space-between\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">校准间隔</span><div style=\"display:flex;align-items:center;gap:8px\"><input type=\"number\" id=\"ds-balance-interval\" min=\"1\" max=\"100\" value=\"10\" style=\"width:60px;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:13px;text-align:center;font-family:system-ui,-apple-system,sans-serif;outline:none\"><span style=\"font-size:12px;color:#9ca3af\">条消息</span></div></div></div></div><div style=\"border-top:1px solid #374151;padding-top:10px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px\">自定义余额</div><div style=\"font-size:12px;color:#6b7280;margin-bottom:8px\">手动设置余额，设置后将覆盖API查询值</div><div style=\"display:flex;gap:6px\"><input id=\"ds-custom-balance\" type=\"number\" step=\"0.01\" placeholder=\"输入余额金额\" style=\"flex:1;padding:8px 10px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:13px;font-family:system-ui,-apple-system,sans-serif;outline:none\"><button id=\"ds-btn-save-balance\" style=\"padding:8px 12px;border:1px solid #065f46;border-radius:6px;background:#065f46;color:#6ee7b7;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">保存</button><button id=\"ds-btn-clear-balance\" style=\"padding:8px 12px;border:1px solid #7f1d1d;border-radius:6px;background:#7f1d1d;color:#fca5a5;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">清除</button></div><div id=\"ds-custom-balance-status\" style=\"font-size:11px;color:#6b7280;margin-top:4px\"></div></div></div><div style=\"border-top:1px solid #374151;padding-top:10px\"><div style=\"display:flex;align-items:center;justify-content:space-between\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">\u8C03\u8BD5\u6A21\u5F0F</span><label style=\"position:relative;display:inline-block;width:44px;height:24px;cursor:pointer\"><input type=\"checkbox\" id=\"ds-debug-mode\" style=\"opacity:0;width:0;height:0\"><span style=\"position:absolute;top:0;left:0;right:0;bottom:0;background:#374151;border-radius:12px;transition:0.3s;cursor:pointer\"><span id=\"ds-debug-mode-slider\" style=\"position:absolute;height:18px;width:18px;left:3px;bottom:3px;background:white;border-radius:50%;transition:0.3s\"></span></span></label></div><div id=\"ds-debug-panel\" style=\"display:none;margin-top:8px\"><div style=\"font-size:11px;color:#6b7280;margin-bottom:8px\">\u6A21\u62DF\u5355\u6B21\u5BF9\u8BDD\u7684token\u6D88\u8017\u53C2\u6570\uFF0C\u4E0D\u4F1A\u4EA7\u751FAAPI\u8D39\u7528</div><div style=\"display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:6px\"><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u7F13\u5B58\u547D\u4E2D tokens</div><input id=\"ds-debug-hit\" type=\"number\" min=\"0\" value=\"10000\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"></div><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u7F13\u5B58\u672A\u547D\u4E2D tokens</div><input id=\"ds-debug-miss\" type=\"number\" min=\"0\" value=\"5000\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"></div><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u8F93\u51FA tokens</div><input id=\"ds-debug-output\" type=\"number\" min=\"0\" value=\"2000\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"></div><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u6A21\u578B</div><select id=\"ds-debug-model\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"><option value=\"deepseek-v4-flash\">deepseek-v4-flash</option><option value=\"deepseek-v4-pro\">deepseek-v4-pro</option></select></div></div><div id=\"ds-debug-status\" style=\"font-size:11px;color:#34d399\"></div></div></div></div><details id=\"ds-help-section\" style=\"margin-bottom:12px;border:1px solid #374151;border-radius:8px;overflow:hidden\"><summary id=\"ds-help-header\" style=\"padding:10px 12px;background:#0e1520;cursor:pointer;display:flex;justify-content:space-between;align-items:center;list-style:none\"><div style=\"display:flex;align-items:center;gap:8px\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">使用说明</span><span style=\"font-size:10px;color:#6b7280\">release1.51</span></div><span id=\"ds-help-arrow\" style=\"font-size:12px;color:#6b7280;transition:transform 0.2s\">▼</span></summary><div id=\"ds-help-content\" style=\"padding:12px;background:#060a10;font-size:12px;color:#9ca3af;line-height:1.6;font-family:system-ui,-apple-system,sans-serif\"><div style=\"margin-bottom:12px\"><div style=\"font-size:11px;color:#f87171;font-weight:600;margin-bottom:4px\">⚠️ 安全提示</div><div>在本插件中填入API密钥存在安全风险。密钥存储在SillyTavern变量系统中，建议使用权限受限的API密钥。</div></div><div style=\"margin-bottom:12px\"><div style=\"font-size:11px;color:#60a5fa;font-weight:600;margin-bottom:4px\">ℹ️ 使用方法</div><div><div>1. 输入API密钥并保存</div><div>2. 点击\"查询\"获取余额</div><div>3. 正常对话，插件自动统计</div><div>4. 新建/切换存档</div><div>5. 选择\"全部存档\"查看合并统计</div></div></div><div><div style=\"font-size:11px;color:#a78bfa;font-weight:600;margin-bottom:4px\">✨ 关于</div><div>本插件完全由AI编写，版本 release1.51</div></div></div></details><div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:12px\"><div style=\"font-size:14px;font-weight:600;color:#e5e7eb;display:flex;align-items:center;gap:8px\"><div style=\"width:3px;height:14px;background:#818cf8;border-radius:2px\"></div><span>统计概览</span><span id=\"ds-save-time\" style=\"font-size:11px;color:#6b7280;font-weight:400\"></span></div><div style=\"display:flex;gap:6px\"><button id=\"ds-btn-refresh\" style=\"padding:6px 12px;border:1px solid #374151;border-radius:6px;background:#0e1520;color:#e5e7eb;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">刷新</button><button id=\"ds-btn-clear\" style=\"padding:6px 12px;border:1px solid #7f1d1d;border-radius:6px;background:#7f1d1d;color:#fca5a5;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">清空</button></div></div><div class=\"ds-grid-3\" style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:16px\"><div style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px\">总消耗</div><div style=\"font-size:20px;font-weight:700;color:#f3f4f6;font-family:system-ui,-apple-system,sans-serif\"><span id=\"ds-total-cost\">¥0.00</span></div><div id=\"ds-total-tokens\" style=\"font-size:12px;color:#6b7280;margin-top:6px;font-weight:500\">0 tokens</div></div><div style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px\">加权缓存命中率</div><div style=\"font-size:20px;font-weight:700;color:#34d399;font-family:system-ui,-apple-system,sans-serif\"><span id=\"ds-weighted-rate\">0%</span></div><div id=\"ds-rounds\" style=\"font-size:12px;color:#6b7280;margin-top:6px;font-weight:500\">基于 0 轮</div></div><div style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px\">平均每轮</div><div style=\"font-size:20px;font-weight:700;color:#f3f4f6;font-family:system-ui,-apple-system,sans-serif\"><span id=\"ds-avg-cost\">¥0.00</span></div><div id=\"ds-avg-tokens\" style=\"font-size:12px;color:#6b7280;margin-top:6px;font-weight:500\">0 tokens</div></div><div style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px\">预计节省</div><div style=\"font-size:20px;font-weight:700;color:#34d399;font-family:system-ui,-apple-system,sans-serif\"><span id=\"ds-savings\">¥0.00</span></div><div id=\"ds-savings-tokens\" style=\"font-size:12px;color:#6b7280;margin-top:6px;font-weight:500\">0 tokens</div></div><div style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px\">支出在输入</div><div style=\"font-size:20px;font-weight:700;color:#f3f4f6;font-family:system-ui,-apple-system,sans-serif\"><span id=\"ds-input-cost\">¥0.00</span></div><div id=\"ds-input-tokens\" style=\"font-size:12px;color:#6b7280;margin-top:6px;font-weight:500\">0 tokens</div></div><div style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.5px\">支出在输出</div><div style=\"font-size:20px;font-weight:700;color:#f3f4f6;font-family:system-ui,-apple-system,sans-serif\"><span id=\"ds-output-cost\">¥0.00</span></div><div id=\"ds-output-tokens\" style=\"font-size:12px;color:#6b7280;margin-top:6px;font-weight:500\">0 tokens</div></div></div><div style=\"font-size:14px;font-weight:600;color:#e5e7eb;margin-bottom:12px;display:flex;align-items:center;gap:8px\"><div style=\"width:3px;height:14px;background:#818cf8;border-radius:2px\"></div>最新一条</div><div id=\"ds-latest\" style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px;margin-bottom:16px\"><div style=\"text-align:center;padding:16px;color:#6b7280;font-weight:500;font-size:13px\">等待第一次对话...</div></div><div style=\"font-size:14px;font-weight:600;color:#e5e7eb;margin-bottom:12px;display:flex;align-items:center;gap:8px\"><div style=\"width:3px;height:14px;background:#818cf8;border-radius:2px\"></div>历史记录</div><div id=\"ds-history\"><div style=\"text-align:center;padding:16px;color:#6b7280;font-weight:500;font-size:13px\">暂无历史记录</div></div>";
  var TARGET_API = '/api/backends/chat-completions/generate';
  var KEY_STORAGE = 'ds_api_key';
  var BALANCE_STORAGE = 'ds_balance_data';
  var SAVES_STORAGE = 'ds_saves';
  var CURRENT_SAVE_KEY = 'ds_current_save';
  var SETTINGS_STORAGE = 'ds_settings';
  var MESSAGE_COUNT_STORAGE = 'ds_message_count';
  var CUSTOM_BALANCE_STORAGE = 'ds_custom_balance';

  function saveWithRetry(key, value) { for (var i = 0; i < 3; i++) { try { var v = getAllVariables(); v[key] = value; replaceVariables(v); return true; } catch(e) {} } return false; }
  function loadWithRetry(key) { for (var i = 0; i < 3; i++) { try { var v = getAllVariables(); return v[key] || null; } catch(e) {} } return null; }
  function saveToLS(key, value) { try { localStorage.setItem('ds_' + key, value); } catch(e) {} }
  function loadFromLS(key) { try { return localStorage.getItem('ds_' + key); } catch(e) { return null; } }
  function saveData(key, value) { saveWithRetry(key, value); saveToLS(key, value); }
  function loadData(key) { var v = loadWithRetry(key); if (v === null) v = loadFromLS(key); return v; }

  function isMobile() { var p = window.parent || window; return (p.innerWidth || 768) <= 760; } function syncViewportHeight() { try { var p = window.parent || window; var h = (p.visualViewport && p.visualViewport.height) || p.innerHeight || 640; p.document.documentElement.style.setProperty('--ds-vvh', Math.max(320, Math.round(h)) + 'px'); } catch(e) {} } function init() { 
    loadSavedData(); 
    loadCurrentSave(); 
    setupEvents(); 
    createUI(); 
    patchFetch();
    state.panelOpen = false;
    initTimestamp = Date.now();
    isInitDone = true;
    syncViewportHeight();
    try {
      var p = window.parent || window;
      if (p.visualViewport) {
        p.visualViewport.addEventListener('resize', syncViewportHeight, { passive: true });
        p.visualViewport.addEventListener('scroll', syncViewportHeight, { passive: true });
      }
      p.addEventListener('resize', syncViewportHeight, { passive: true });
    } catch(e) {}
    try {
      var p3 = window.parent || window;
      var vw = (p3.innerWidth || 768) > 760 ? 'desktop' : 'mobile';
      p3.addEventListener('resize', function() {
        var nv = (p3.innerWidth || 768) > 760 ? 'desktop' : 'mobile';
        if (vw !== nv) {
          vw = nv;
          var pn = p3.document.getElementById('ds-panel');
          if (pn && pn.classList.contains('ds-open')) {
            pn.classList.add('ds-no-animation');
            setTimeout(function() {
              pn.classList.remove('ds-no-animation');
            }, 30);
          }
        }
      }, { passive: true });
    } catch(e) {}
    try {
      var wp = window.parent || window;
      var wdoc = wp.document;
      var menu = wdoc.getElementById('extensionsMenu');
      if (menu) {
        var container = wdoc.createElement('div');
        container.id = 'ds_wand_container';
        container.className = 'extension_container';
        container.innerHTML = '<div id="ds_wand_entry" class="list-group-item flex-container flexGap5"><div class="fa-solid fa-chart-bar extensionsMenuExtensionButton" /></div>DeepSeek使用预测</div>';
        menu.appendChild(container);
        var wandBtn = wdoc.getElementById('ds_wand_entry');
        if (wandBtn) { wandBtn.addEventListener('click', function() { togglePanel(); }); }
      }
    } catch(e) {}
  }
  function loadSavedData() { 
    try { 
      state.apiKey = decryptKey(loadData(KEY_STORAGE)) || ''; 
      var bd = loadData(BALANCE_STORAGE); 
      if (bd) { try { state.balance = JSON.parse(bd); } catch(e) {} }
      var cbd = loadData(CUSTOM_BALANCE_STORAGE);
      if (cbd) { state.customBalance = cbd; }
      var sd = loadData(SAVES_STORAGE); 
      if (sd) { try { state.saves = JSON.parse(sd); } catch(e) {} }
      var std = loadData(SETTINGS_STORAGE); 
      if (std) { try { state.settings = JSON.parse(std); } catch(e) {} }
      state.messageCount = parseInt(loadData(MESSAGE_COUNT_STORAGE) || '0');
    } catch(e) {
      console.error('[DS] loadSavedData error:', e);
    }
  }
  function saveSaves() { saveData(SAVES_STORAGE, JSON.stringify(state.saves)); }
  function saveCurrentSaveKey() { saveData(CURRENT_SAVE_KEY, state.currentSave); }
  function saveSettings() { saveData(SETTINGS_STORAGE, JSON.stringify(state.settings)); }
  function saveMessageCount() { saveData(MESSAGE_COUNT_STORAGE, String(state.messageCount)); }
  // 面板状态不保存，每次刷新默认关闭

  function calculateRemainingRounds(stats) {
    var bal = (state.customBalance !== null && state.customBalance !== '') ? parseFloat(state.customBalance) : (state.balance && state.balance.balance ? parseFloat(state.balance.balance) : null);
    if (bal === null || isNaN(bal)) return null;
    var s = stats || getSelectedSave();
    if (!s || (s.rounds || 0) === 0) return null;
    var history = s.history || [];
    if (history.length === 0) {
      var avg = (s.total_cost || 0) / s.rounds;
      if (avg <= 0) return null;
      return Math.floor(bal / avg);
    }
    var alpha = 0.3;
    var ewma = history[history.length - 1].cost || 0;
    for (var i = history.length - 2; i >= 0; i--) {
      ewma = alpha * (history[i].cost || 0) + (1 - alpha) * ewma;
    }
    if (ewma <= 0) return null;
